    {
      "keystrokes": "python3 - <<'PY'\nmods=['cv2','PIL','numpy','av','moviepy','imageio','skimage','pytesseract','easyocr']\nfor m in mods:\n    try:\n        __import__(m)\n        print(m, 'OK')\n    except Exception as e:\n        print(m, 'NO', type(e).__name__)\nPY\n",
      "duration": 0.1
    },
    {
      "keystrokes": "find / -maxdepth 4 \\( -name 'ffmpeg' -o -name 'ffprobe' -o -name 'tesseract' \\) 2>/dev/null | head -20\n",
